INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (2207, 211832, 13, 2342, '[转贴]刻在旧木课桌上的吻(女版)', '我的蓝裙子被风拂动，我的心惆怅地融化了。 上了大学以后，天的颜色好像都变得比以前蓝了。宿舍的窗外是长满银杏树的街道，早上会有好多金色的叶子落在阳台上。那时候，我十八岁，是一个喜欢银杏树、喜欢蓝裙子、经常坐在阳台上看小说的女孩子。 常常和同伴去外面的超市买950毫升的牛奶和漂亮纸口袋装的话梅，然后一边吃着冰淇淋一边踢着黄叶子走过暮色初起的街。因为我决意要做一个散淡的人，所以过着无所事事的读书生涯，心理时常充满莫名的忧伤。 因为心理的忧伤，我便喜欢一个人。我也不知道怎么会注意到他，只是有一段时间，我总会遇见他，看到他不经意地从我身边走过，或是在同一个场合出现，我都会很紧张。 坐在图书馆的阅览室，笔直看过去，又是他！那么一双的闪亮的眼睛，不怀好意却又那么英俊，我知道男人不应该靠一副脸容取胜，但我实在是被他的容颜征服。那眼睛，可以看牢一个人,一眨不眨，黑眼珠的颜色深浓，白眼珠却是残酷，睫毛更有一种羞涩的意思，他太奇怪了。我喜欢他。 1997年4月25日傍晚我坐在阳台上的时候，忽然他从下面经过，他穿黑色T恤，戴一顶鸭舌帽，帽子反着戴，把鸭舌头遮着后脑勺。他手里抱着一个球，像个小流氓似的悠闲地走向远处的篮球场。我的蓝裙子被风拂动，我的心惆怅地融化了。 我便跑去蓝球场，远远地看着他与别人打球。他们都是男生，有几个人注意到我了，便互相转告，大家都看我，他也几次回过身来，但是他没有表情。 他们并没有起哄，只是认真地打球，我突然觉得自己又土有又傻，便走了。 我决定忘记他。但是转眼机缘又来了，开运动会时，我又看见黑色恤的他，他的反戴的帽子，小流氓似的走路姿势，淡漠的神情。那一天，我和好朋友一起走，我告诉好朋友哪个男生我喜欢。 她了看他，对我说：“看起来不象好人吧。”我说：“对。”我们尾随他到了他们班的位置，我这下看清楚，他是管理系的，比我高一年级。 从此我对管理系的人印象特别好，看见他们便微笑，真是爱屋及乌，而且也时常修习自己的言行举止，立志做到不论何时遇见他，都要他看到一个完美的我。我还设想很多与他相遇的方式，比如我抱着书从教室里出来，他一下子撞到我；或者某天穿一条美丽的裙子，他注意到我；或者，我被车撞倒，他正巧经过…… 但是我设想的事情都没有发生。真正的相遇很简单。那天我在图书馆又看到他，我们俩，只隔着一张木桌，我便写了纸条，而且也没有任何修辞，只是写上我的名字，说想和他交往。我不敢看他，把头低在书上。然后，当我抬起头来，发现他已经走了，当时我真是好后悔，被拒绝的滋味是有一刻甚至想自杀，我便扶在桌上，想哭又哭不出。 到很晚，我才走，整个人像被雨淋湿了，无比的颓丧，然而，当我走到大门口时，我看见他正坐在台阶上，他转过身，看到我，笑了，说：“笨蛋！”我惊喜的差点跳起来，然后他牵起我的手，把我送到宿舍门口，然后他向我要我的图书证，把里面的一寸照片撕下来，放自己的口袋里,就走了。 我们在约会，我特意穿上为了见他才买的新裙子，我想他一定也感觉到我这么隆重的出场是为了什么。他笑了笑。我没走到很远的地方，回来时他把我提到过的东西，比如侦探小说，他的照片，张楚的歌，全都拿给我。 紧接着我们系去承德考察，我便日日夜夜思念他。去到陌生的城市，看到好的东西都想买给他，觉得每一首情歌都是在描述我们。买了好吃的无花果，这种外表丑陋却无比甜蜜的小果实，有许多细小的籽粒，我回来时，和他一起却看电影，就吃无花果，吃得两个人又快乐又难受，这便是初恋的滋味吧。回来的路上，走过一棵大槐树下，我们互望对方，他的眼神看起来又不怀好意了，但是我忽然笑起来，想到两个人满嘴无花果籽粒，怎么能够接吻呢，我便转过头去。 我问他：“欧阳梓，你爱我吗？”他说：不知道，不清楚。他只是用眼睛看着我，笑了笑。后来有一天，他找到我对我说，他原来的女朋友回来了，他和她在一起。当时我站在他面前，并没有像电影里的女孩子那样优雅地给他一巴掌，我气得抓起地上的石头打他。他的胸口中招，但是没说一句话，只是沉默地走了，倒是我哭哭啼啼地受了很多伤。 刻在旧木课桌上的初吻(下) 我又恢复到散淡的读书生涯里去。他在没有让我见到他，是啊，还什么见面的必要呢，像他这样的人，我应该有所预感的，他怎么一生只有一个女孩？而我需要的是温厚持久的爱情，与他能给我的恰恰相反。那天下午我坐在阳台上看书，忽然流下眼泪来，时间过的很快，他毕业了。 正是毕业生离校的日子，宿舍里很乱，有些人在哭，有些人吃东西，有些人去上自 习，就在那个晚上，他忽然出现，那晚我们寝室只剩下我一个人，他推门便进来了，一句话也没说，就把我拎了出去。 我们走到电影院的那棵槐树下，他一把将我推倒在树干上，然后说，秦榛，我想亲 你。我没有挣扎，只是轻轻闭上眼睛，问他一句：“欧阳梓，你爱我吗？”那时我才发现，其实我一直很不争气地爱着他。他的呼吸喷在我脸上，进在咫尺，却忽然远去。 他放开了我，没有回答我的问题，只是对我说了一句：“笨蛋。”这次之后我想我是死心了，我忽然会聪明地分析起我和他的关系了――我只不过是他寂寞时候的一个玩具，他对我只不过是戏弄戏弄。这样想着，我也到了毕业的时候，我有了男朋友，是校长的儿子，因为他喜欢我，而他爸喜欢他，所以我们都留了校，并且很快将要结婚，住进那四室两厅有花园的小楼里。 我的生活安逸无聊，只需要每个星期一去教室点学生的名字，把没有来的学生名下画个红线，也不会像别的辅导员那样想办法整顿，我是个出了名的软弱派，很受学生欢迎。 时间过的好快啊，转眼，又一批新生来报到了，系里开学生大会那天，我在很多人的名字里,忽然看到欧阳权三个字，当我点到他，他站起来，我惊呆了。 当然不是欧阳梓的复制。小权是小权，是欧阳梓的一个远方亲戚，一个活泼的爱说话的孩子，他告诉我欧阳梓现在很辛福。 我便这样通过小权打听到欧阳梓的情况，我知道这样做是不对的，但是我无法控制自己，再后来我出差的时候，就去了他的家乡。 我按照小权给我的地址，来到欧阳梓的单位，他看到我，冲我笑了笑，他从办公室走出来，阳光洒了一肩，我们只是无话可说，他最后带我到他家里吃饭。 他们已经有了一个孩子，生活很好很平淡。他妻子显然不知道我与欧阳梓的从前，待我很热情。吃完饭，我该走了，可是，多年前我想到的一句话和一个吻，却始终未得到。 有时候我是很执拗的，我让欧阳梓送我。走在路上，我问他，欧阳梓，你到底爱不爱我？你为什么要变成这样？他忽然急了，说：你要我说什么呢，我大学时弄大了人家的肚子，总不能不负责任吧。我一辈子只爱她一个人，已经决定了！我根本不爱你。 我们就这样很淡的分别了。回去后，我开始张罗结婚的事。 人们说，大多数人的初恋都是失败的，我也不过是个平凡的，又怎么会幸免呢。 这是2000年3月，一个春天的下午，学校大扫除，我经过教室的时候，一年级的同学突然大声叫我，他们把我拉到一张旧书桌前，那是一张很旧很旧的木书桌，放在教室最后一排，已经被蛀虫咬得酥散了，可是那上面的字却依然清晰，我看到了我的名字，和一些歪歪扭扭的字迹：榛生，但愿你永远也别看到，如果你看到了，我就不会安心地过完下半生了。我爱你。我怎么会不爱你呢。我只是很后悔自己作错了事，它带来惩罚就是让我永远不能去吻我真正爱的人，也不能与她生活在一起。 后面，有一个大大的唇印，印在另一张红色圆珠笔画的唇印上。 同学们鼓起掌来，我在孩子的善意里也笑了，“这是谁的恶作剧呀。”我说。但是转身却流下 了眼泪。。。。。。', '我的蓝裙子被风拂动，我的心惆怅地融化了。 上了大学以后，天的颜色好像都变得比以前蓝了。宿舍的窗外是长满银杏树的街道，早上会有好多金色的叶子落在阳台上。那时候，我十八岁，是一个喜欢银杏树、喜欢蓝裙子、经常坐在阳台上看小说的女孩子。 常常和同伴去外面的超市买950毫升的牛奶和漂亮纸口袋装的话梅，然后一边吃着冰淇淋一边踢着黄叶子走过暮色初起的街。因为我决意要做一个散淡的人，所以过着无所事事的读书生涯，心理时常充满莫名的忧伤。 因为心理的忧伤，我便喜欢一个人。我也不知道怎么会注意到他，只是有一段时间，我总会遇见他，看到他不经意地从我身边走过，或是在同一个场合出现，我都会很紧张。 坐在图书馆的阅览室，笔直看过去，又是他！那么一双的闪亮的眼睛，不怀好意却又那么英俊，我知道男人不应该靠一副脸容取胜，但我实在是被他的容颜征服。那眼睛，可以看牢一个人,一眨不眨，黑眼珠的颜色深浓，白眼珠却是残酷，睫毛更有一种羞涩的意思，他太奇怪了。我喜欢他。 1997年4月25日傍晚我坐在阳台上的时候，忽然他从下面经过，他穿黑色T恤，戴一顶鸭舌帽，帽子反着戴，把鸭舌头遮着后脑勺。他手里抱着一个球，像个小流氓似的悠闲地走向远处的篮球场。我的蓝裙子被风拂动，我的心惆怅地融化了。 我便跑去蓝球场，远远地看着他与别人打球。他们都是男生，有几个人注意到我了，便互相转告，大家都看我，他也几次回过身来，但是他没有表情。 他们并没有起哄，只是认真地打球，我突然觉得自己又土有又傻，便走了。 我决定忘记他。但是转眼机缘又来了，开运动会时，我又看见黑色恤的他，他的反戴的帽子，小流氓似的走路姿势，淡漠的神情。那一天，我和好朋友一起走，我告诉好朋友哪个男生我喜欢。 她了看他，对我说：“看起来不象好人吧。”我说：“对。”我们尾随他到了他们